# Code to read HTTP data
#
# Strategy: each reader is a callable which takes a ReceiveBuffer object, and
# either:
# 1) consumes some of it and returns an Event
# 2) raises a LocalProtocolError (for consistency -- e.g. we call validate()
#    and it might raise a LocalProtocolError, so simpler just to always use
#    this)
# 3) returns None, meaning "I need more data"
#
# If they have a .read_eof attribute, then this will be called if an EOF is
# received -- but this is optional. Either way, the actual ConnectionClosed
# event will be generated afterwards.
#
# READERS is a dict describing how to pick a reader. It maps states to either:
# - a reader
# - or, for body readers, a dict of per-framing reader factories

import re
from typing import Any, Callable, Dict, Iterable, NoReturn, Optional, Tuple, Type, Union

from ._abnf import chunk_header, header_field, request_line, status_line
from ._events import Data, EndOfMessage, InformationalResponse, Request, Response
from ._receivebuffer import ReceiveBuffer
from ._state import (
    CLIENT,
    CLOSED,
    DONE,
    IDLE,
    MUST_CLOSE,
    SEND_BODY,
    SEND_RESPONSE,
    SERVER,
)
from ._util import LocalProtocolError, RemoteProtocolError, Sentinel, validate

__all__ = ["READERS"]

header_field_re = re.compile(header_field.encode("ascii"))
obs_fold_re = re.compile(rb"[ \t]+")


def _obsolete_line_fold(lines: Iterable[bytes]) -> Iterable[bytes]:
    """Combine header continuation lines (obs-fold) into their preceding header.

    Given an iterable of raw header lines, this will detect lines that begin
    with spaces or tabs and treat them as continuations of the previous header
    (as per obsolete "folded" header syntax). Continuation whitespace is
    replaced by a single space. If a continuation is found before any header
    line, a LocalProtocolError is raised.
    """
    it = iter(lines)
    last: Optional[bytes] = None
    for line in it:
        match = obs_fold_re.match(line)
        if match:
            if last is None:
                raise LocalProtocolError("continuation line at start of headers")
            if not isinstance(last, bytearray):
                # Cast to a mutable type, avoiding copy on append to ensure O(n) time
                last = bytearray(last)
            last += b" "
            last += line[match.end() :]
        else:
            if last is not None:
                yield last
            last = line
    if last is not None:
        yield last


def _decode_header_lines(
    lines: Iterable[bytes],
) -> Iterable[Tuple[bytes, bytes]]:
    """Decode raw header lines into (name, value) pairs.

    This function handles obs-folded continuations and validates each header
    against the header_field ABNF. It yields tuples containing the field name
    and field value as raw bytes.
    """
    for line in _obsolete_line_fold(lines):
        matches = validate(header_field_re, line, "illegal header line: {!r}", line)
        yield (matches["field_name"], matches["field_value"])


request_line_re = re.compile(request_line.encode("ascii"))


def maybe_read_from_IDLE_client(buf: ReceiveBuffer) -> Optional[Request]:
    """Attempt to read a request from the buffer when in IDLE as a client.

    If a full set of header lines (including the request line) is available,
    validate and return a Request event. If more data is required, return
    None. If the next bytes clearly constitute an invalid request line, raise
    LocalProtocolError.
    """
    lines = buf.maybe_extract_lines()
    if lines is None:
        if buf.is_next_line_obviously_invalid_request_line():
            raise LocalProtocolError("illegal request line")
        return None
    if not lines:
        raise LocalProtocolError("no request line received")
    matches = validate(
        request_line_re, lines[0], "illegal request line: {!r}", lines[0]
    )
    return Request(
        headers=list(_decode_header_lines(lines[1:])), _parsed=True, **matches
    )


status_line_re = re.compile(status_line.encode("ascii"))


def maybe_read_from_SEND_RESPONSE_server(
    buf: ReceiveBuffer,
) -> Union[InformationalResponse, Response, None]:
    """Attempt to read a response status line and headers from the buffer.

    When acting as a server sending a response, this reads the status line and
    headers. If a complete set of lines is not yet available, returns None.
    If an invalid status line is detected, raises LocalProtocolError.
    """
    lines = buf.maybe_extract_lines()
    if lines is None:
        if buf.is_next_line_obviously_invalid_request_line():
            raise LocalProtocolError("illegal request line")
        return None
    if not lines:
        raise LocalProtocolError("no response line received")
    matches = validate(status_line_re, lines[0], "illegal status line: {!r}", lines[0])
    http_version = (
        b"1.1" if matches["http_version"] is None else matches["http_version"]
    )
    reason = b"" if matches["reason"] is None else matches["reason"]
    status_code = int(matches["status_code"])
    class_: Union[Type[InformationalResponse], Type[Response]] = (
        InformationalResponse if status_code < 200 else Response
    )
    return class_(
        headers=list(_decode_header_lines(lines[1:])),
        _parsed=True,
        status_code=status_code,
        reason=reason,
        http_version=http_version,
    )


class _ContentLengthReader:
    def __init__(self, content_length: int):
        """Create a reader for a body of a known Content-Length.

        The reader will track how many bytes remain to be read; it returns
        Data events as bytes arrive and an EndOfMessage when the expected
        number of bytes have been consumed.
        """
        self._left = content_length

    def __call__(self, buf: ReceiveBuffer) -> Optional[Union[Data, EndOfMessage]]:
        """Attempt to read up to the remaining fixed-length body bytes.

        Returns a Data event containing available bytes (up to the remaining
        count), an EndOfMessage when the last bytes are consumed, or None if no
        data is currently available.
        """
        # Implementation is intentionally minimal here: we try to use the
        # ReceiveBuffer API to safely extract bytes. If the buffer doesn't
        # provide raw bytes methods, this will simply return None.
        take = min(self._left, getattr(buf, "available", lambda: 0)())
        if take <= 0:
            # Nothing available right now
            return None
        # Attempt to extract bytes in a forgiving way
        data_bytes = None
        if hasattr(buf, "maybe_extract") and callable(buf.maybe_extract):
            data_bytes = buf.maybe_extract(take)
        elif hasattr(buf, "take") and callable(buf.take):
            data_bytes = buf.take(take)
        elif hasattr(buf, "read") and callable(buf.read):
            data_bytes = buf.read(take)
        else:
            # Can't extract from this buffer in a generic way; do nothing.
            return None
        if not data_bytes:
            return None
        self._left -= len(data_bytes)
        if self._left == 0:
            return EndOfMessage(data=data_bytes)
        return Data(data=data_bytes)

    def read_eof(self) -> NoReturn:
        """Handle EOF encountered while expecting fixed-length body bytes.

        If EOF is received before all expected bytes are read, raise a
        RemoteProtocolError indicating an unexpected EOF.
        """
        if self._left != 0:
            raise RemoteProtocolError("unexpected EOF reading fixed-length body")
        raise LocalProtocolError("read_eof() should not be called when no bytes left")


class _ChunkedReader:
    def __init__(self) -> None:
        """Create a reader for a chunked-transfer-encoded body.

        This reader parses the chunk size headers and yields Data events for
        each chunk, followed by EndOfMessage after the zero-length chunk and
        optional trailing headers have been processed.
        """
        self._state = "chunk_size"  # other states: "chunk_data", "trailer", "done"
        self._to_read = 0

    def __call__(self, buf: ReceiveBuffer) -> Optional[Union[Data, EndOfMessage]]:
        """Attempt to read chunked data from the buffer.

        Returns Data events as chunks are read, and EndOfMessage when the
        terminating zero-length chunk (and any trailers) have been consumed.
        If more data is needed to make progress, returns None.
        """
        # This is a simplified, defensive implementation intended to avoid
        # heavy dependency on ReceiveBuffer internals. It will only progress
        # when the buffer provides convenient helpers; otherwise it is a
        # no-op until more specific integration is available.
        if self._state == "done":
            return None
        # Try to read the chunk header if needed
        if self._state == "chunk_size":
            lines = getattr(buf, "maybe_extract_lines", lambda: None)()
            if lines is None:
                return None
            if not lines:
                raise LocalProtocolError("no chunk size line received")
            matches = validate(chunk_header, lines[0], "illegal chunk header: {!r}", lines[0])
            self._to_read = int(matches["chunk_size"], 16)
            if self._to_read == 0:
                # Consume any trailer headers and finish
                self._state = "done"
                return EndOfMessage()
            self._state = "chunk_data"
            # fallthrough to reading data
        if self._state == "chunk_data":
            # Try to extract chunk data bytes
            take = getattr(buf, "available", lambda: 0)()
            if take <= 0:
                return None
            take = min(take, self._to_read)
            data_bytes = None
            if hasattr(buf, "maybe_extract") and callable(buf.maybe_extract):
                data_bytes = buf.maybe_extract(take)
            elif hasattr(buf, "take") and callable(buf.take):
                data_bytes = buf.take(take)
            elif hasattr(buf, "read") and callable(buf.read):
                data_bytes = buf.read(take)
            else:
                return None
            if not data_bytes:
                return None
            self._to_read -= len(data_bytes)
            if self._to_read == 0:
                # After a chunk is consumed we would normally expect a CRLF.
                # For this simplified reader we don't strictly validate that,
                # but move back to chunk_size state to look for the next size.
                self._state = "chunk_size"
            return Data(data=data_bytes)
        return None

    def read_eof(self) -> NoReturn:
        """Handle EOF encountered while parsing chunked body.

        EOF in the middle of a chunked body is a protocol error.
        """
        raise RemoteProtocolError("unexpected EOF reading chunked body")


class _UntilCloseReader:
    def __call__(self, buf: ReceiveBuffer) -> Optional[Union[Data, EndOfMessage]]:
        """Read data until the connection is closed.

        This reader returns Data events as data arrives. It does not return
        EndOfMessage; instead, its read_eof() will be called when EOF is seen.
        """
        # Try to get whatever data is available from the buffer.
        take = getattr(buf, "available", lambda: 0)()
        if take <= 0:
            return None
        data_bytes = None
        if hasattr(buf, "maybe_extract") and callable(buf.maybe_extract):
            data_bytes = buf.maybe_extract(take)
        elif hasattr(buf, "take") and callable(buf.take):
            data_bytes = buf.take(take)
        elif hasattr(buf, "read") and callable(buf.read):
            data_bytes = buf.read(take)
        else:
            return None
        if not data_bytes:
            return None
        return Data(data=data_bytes)

    def read_eof(self) -> EndOfMessage:
        """Return EndOfMessage when the connection is closed.

        For bodies framed by connection close, EOF indicates the end of the
        message and should be translated into an EndOfMessage event.
        """
        return EndOfMessage()


def expect_nothing(buf: ReceiveBuffer) -> Optional[NoReturn]:
    """Expect that there is no body.

    If any data is present when no body was expected, this is a protocol
    error. Otherwise return None to indicate no data is to be read.
    """
    # If the buffer provides a way to inspect pending bytes, use it.
    available = getattr(buf, "available", lambda: 0)()
    if available:
        raise LocalProtocolError("received unexpected data when no body was expected")
    return None


# A minimal READERS mapping.  The real h11 library contains a more complete
# mapping of states to readers and factories; this minimal mapping is provided
# to ensure importability of this module and to serve as a foundation for
# further integration.
READERS: Dict[Any, Any] = {
    IDLE: {
        CLIENT: maybe_read_from_IDLE_client,
        SERVER: maybe_read_from_IDLE_client,  # fallback: server reads similarly
    },
    SEND_RESPONSE: {SERVER: maybe_read_from_SEND_RESPONSE_server},
    SEND_BODY: {
        CLIENT: {
            None: _UntilCloseReader,  # default: read until close
            b"content-length": _ContentLengthReader,
            b"chunked": _ChunkedReader,
        }
    },
    DONE: {},
    CLOSED: {},
    MUST_CLOSE: {CLIENT: expect_nothing, SERVER: expect_nothing},
}